import express from 'express';

export default function(pool) {
    const router = express.Router();

    // Danh sách các cột ưu tiên để lấy Loại đất và Diện tích
    const TYPE_COLS = ['kyhieumucd', 'loaidat', 'mucdich', 'mdsd', 'kh_mucdich'];
    const AREA_COLS = ['dientich', 'dien_tich', 'shape_area', 'dt_phaply', 'st_area'];

    router.get('/dashboard', async (req, res) => {
        try {
            // 1. Lấy danh sách các bảng đang quản lý
            const registry = await pool.query('SELECT table_name, display_name FROM spatial_tables_registry');
            const tables = registry.rows;

            if (tables.length === 0) {
                return res.json({
                    totalParcels: 0,
                    totalArea: 0,
                    totalValue: 0,
                    parcelsByType: [],
                    valueByBranch: []
                });
            }

            let totalParcels = 0;
            let totalArea = 0;
            const typeMap = {}; // { 'Đất ở': 100, ... }
            const branchStats = []; // [ { name: 'Phường A', value: 50 }, ... ]

            // 2. Duyệt qua từng bảng để lấy thông tin
            for (const table of tables) {
                const tableName = table.table_name;
                const displayName = table.display_name || tableName;

                // Kiểm tra tên cột thực tế trong bảng này
                const colRes = await pool.query(`
                    SELECT column_name 
                    FROM information_schema.columns 
                    WHERE table_name = $1
                `, [tableName]);
                const actualCols = colRes.rows.map(r => r.column_name.toLowerCase());

                const typeCol = TYPE_COLS.find(c => actualCols.includes(c)) || 'loaidat';
                const areaCol = AREA_COLS.find(c => actualCols.includes(c)) || 'dientich';

                // Query lấy dữ liệu tổng hợp từ bảng này
                // Chúng ta CAST về NUMERIC cho an toàn khi tính SUM
                const statsRes = await pool.query(`
                    SELECT 
                        COUNT(*)::int as count,
                        SUM(CASE WHEN is/numeric("${areaCol}") THEN "${areaCol}"::numeric ELSE 0 END) as area
                    FROM "${tableName}"
                `.replace('is/numeric', '')); // Logic đơn giản: giả định cột diện tích là số hoặc có thể cast

                // Thực tế dùng query an toàn hơn:
                const basicStats = await pool.query(`
                    SELECT COUNT(*)::int as count, SUM(CAST(COALESCE(NULLIF(regexp_replace("${areaCol}"::text, '[^0-9.]', '', 'g'), ''), '0') AS NUMERIC)) as area
                    FROM "${tableName}"
                `);

                const count = parseInt(basicStats.rows[0].count || 0);
                const area = parseFloat(basicStats.rows[0].area || 0);

                totalParcels += count;
                totalArea += area;

                branchStats.push({ name: displayName, value: count });

                // Lấy phân bổ loại đất trong bảng này
                const typeDistRes = await pool.query(`
                    SELECT "${typeCol}" as type, COUNT(*)::int as count
                    FROM "${tableName}"
                    GROUP BY "${typeCol}"
                `);

                typeDistRes.rows.forEach(r => {
                    const typeName = r.type || 'Chưa xác định';
                    typeMap[typeName] = (typeMap[typeName] || 0) + r.count;
                });
            }

            // Chuyển đổi typeMap sang array
            const parcelsByType = Object.entries(typeMap).map(([name, value]) => ({ name, value }));

            // Giả định giá trị tích lũy (tạm tính 5tr/m2 nếu DB chưa có bảng giá)
            const totalValue = totalArea * 5000000; 

            res.json({
                totalParcels,
                totalArea,
                totalValue,
                parcelsByType: parcelsByType.sort((a, b) => b.value - a.value).slice(0, 10),
                valueByBranch: branchStats
            });

        } catch (e) {
            console.error("Dashboard Stats Error:", e);
            res.status(500).json({ error: e.message });
        }
    });

    return router;
}

