import express from 'express';

export default function(pool) {
    const router = express.Router();

    // Lấy tin nhắn giữa người dùng hiện tại và một người dùng khác
    router.get('/:otherUserId', async (req, res) => {
        const userId = req.headers['x-user-id'];
        const { otherUserId } = req.params;

        try {
            const query = `
                SELECT m.*, u.name as sender_name, u.avatar as sender_avatar
                FROM internal_messages m
                JOIN users u ON m.sender_id = u.id
                WHERE (m.sender_id = $1 AND m.receiver_id = $2)
                   OR (m.sender_id = $2 AND m.receiver_id = $1)
                ORDER BY m.timestamp ASC
            `;
            const result = await pool.query(query, [userId, otherUserId]);
            res.json(result.rows);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    // Gửi tin nhắn mới
    router.post('/', async (req, res) => {
        const userId = req.headers['x-user-id'];
        const { receiverId, content } = req.body;

        try {
            const query = `
                INSERT INTO internal_messages (sender_id, receiver_id, content)
                VALUES ($1, $2, $3) RETURNING *
            `;
            const result = await pool.query(query, [userId, receiverId, content]);
            res.json(result.rows[0]);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    // Đếm số tin nhắn chưa đọc
    router.get('/unread/count', async (req, res) => {
        const userId = req.headers['x-user-id'];
        try {
            const result = await pool.query(
                `SELECT COUNT(*)::int as count FROM internal_messages WHERE receiver_id = $1 AND is_read = false`,
                [userId]
            );
            res.json(result.rows[0]);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    // Đánh dấu đã đọc hội thoại
    router.put('/read/:senderId', async (req, res) => {
        const userId = req.headers['x-user-id'];
        const { senderId } = req.params;
        try {
            await pool.query(
                `UPDATE internal_messages SET is_read = true WHERE receiver_id = $1 AND sender_id = $2`,
                [userId, senderId]
            );
            res.json({ status: 'ok' });
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    return router;
}

