import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Login from './pages/Login';
import MapPage from './pages/MapPage';
import Dashboard from './pages/Dashboard';
import AdminPage from './pages/AdminPage'; 
import UserProfile from './pages/UserProfile';
import Messaging from './pages/Messaging';
import { User, UserRole, SystemSetting } from './types';
import { ShieldAlert, RefreshCw } from 'lucide-react';
import { adminService, authService, API_URL } from './services/mockBackend';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activePage, setActivePage] = useState('map');
  const [showLogin, setShowLogin] = useState(false);
  const [resetToken, setResetToken] = useState<string | null>(null);
  const [verificationToken, setVerificationToken] = useState<string | null>(null);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [systemSettings, setSystemSettings] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
      const params = new URLSearchParams(window.location.search);
      if (params.get('token')) { setResetToken(params.get('token')); setShowLogin(true); }
      if (params.get('verificationToken')) { setVerificationToken(params.get('verificationToken')); setShowLogin(true); }

      const boot = async () => {
          setLoading(true);
          try {
              const settings: SystemSetting[] = await adminService.getSettings();
              const settingsMap: Record<string, string> = {};
              settings.forEach(s => settingsMap[s.key] = s.value);
              setSystemSettings(settingsMap);

              if (settingsMap['system_name']) document.title = settingsMap['system_name'];

              if (settingsMap['site_favicon']) {
                  const faviconLink = document.getElementById('favicon') as HTMLLinkElement;
                  if (faviconLink) {
                      let favUrl = settingsMap['site_favicon'];
                      if (favUrl.startsWith('/uploads')) {
                          const baseUrl = API_URL.endsWith('/') ? API_URL.slice(0, -1) : API_URL;
                          favUrl = `${baseUrl}${favUrl}`;
                      }
                      faviconLink.href = favUrl;
                  }
              }

              const savedUser = localStorage.getItem('geo_user');
              if (savedUser) {
                  const localUser = JSON.parse(savedUser);
                  setUser(localUser);

                  try {
                      const freshUser = await authService.getProfile(localUser.id);
                      if (freshUser) {
                          const updatedUser = { ...localUser, ...freshUser };
                          setUser(updatedUser);
                          localStorage.setItem('geo_user', JSON.stringify(updatedUser));
                      }
                  } catch (syncErr) {
                      console.warn("Không thể đồng bộ hồ sơ từ server, sử dụng dữ liệu offline.");
                  }
              }
          } catch (e) {
              console.error("Khởi động thất bại", e);
          } finally {
              setLoading(false);
          }
      };
      boot();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('geo_user', JSON.stringify(loggedInUser));
    setShowLogin(false);
    setResetToken(null);
    setVerificationToken(null);
    setActivePage(loggedInUser.role === UserRole.ADMIN ? 'admin' : 'dashboard');
  };

  const handleUpdateUser = (updatedUser: User) => {
      setUser(updatedUser);
      localStorage.setItem('geo_user', JSON.stringify(updatedUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('geo_user');
    setActivePage('map');
  };

  if (loading) return (
      <div className="h-screen w-full bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
          <RefreshCw className="animate-spin text-blue-500" size={48} />
          <p className="font-display uppercase tracking-widest text-sm">Khởi động GeoMaster...</p>
      </div>
  );

  if (showLogin) return (
      <Login 
        onLogin={handleLogin} 
        onCancel={() => { setShowLogin(false); setResetToken(null); setVerificationToken(null); }}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
        footerText={systemSettings['footer_text']}
        allowRegistration={systemSettings['allow_registration'] === 'true'}
        initialToken={resetToken}
        verificationToken={verificationToken}
      />
  );

  if (systemSettings['maintenance_mode'] === 'true' && user?.role !== UserRole.ADMIN) return (
      <div className="h-screen w-full bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
          <ShieldAlert className="text-orange-500 mb-6" size={64} />
          <h1 className="text-3xl font-display font-bold text-white mb-2 uppercase">Hệ thống bảo trì</h1>
          <button onClick={() => setShowLogin(true)} className="text-blue-500 hover:underline mt-4">Dành cho Quản trị viên</button>
      </div>
  );

  const renderContent = () => {
    switch (activePage) {
      case 'dashboard': return user ? <Dashboard user={user} /> : null;
      case 'map': return <MapPage user={user} systemSettings={systemSettings} />;
      case 'profile': return user ? <UserProfile user={user} onUpdateUser={handleUpdateUser} /> : null;
      case 'messaging': return user ? <Messaging user={user} /> : null;
      case 'admin': return user?.role === UserRole.ADMIN ? <AdminPage systemName={systemSettings['system_name']} logoUrl={systemSettings['site_logo']} /> : null;
      default: return <MapPage user={user} systemSettings={systemSettings} />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-gray-900 overflow-hidden font-sans relative">
      <Sidebar 
        user={user} 
        activePage={activePage} 
        onNavigate={setActivePage} 
        onLogout={handleLogout}
        onLoginClick={() => setShowLogin(true)}
        onCollapse={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        isCollapsed={isSidebarCollapsed}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
      />
      <main className="flex-1 h-full relative overflow-hidden bg-gray-100 flex flex-col transition-all">
        {renderContent()}
      </main>
    </div>
  );
};

