import express from 'express';

export default function(pool, logSystemAction) {
    const router = express.Router();

    // --- BRANCHES ---
    router.get('/branches', async (req, res) => {
        try { res.json((await pool.query(`SELECT * FROM branches ORDER BY name`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.post('/branches', async (req, res) => {
        try {
            const id = 'br-' + Date.now();
            await pool.query(`INSERT INTO branches (id, code, name, address) VALUES ($1, $2, $3, $4)`, [id, req.body.code, req.body.name, req.body.address]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- LAND PRICES ---
    router.get('/land-prices', async (req, res) => {
        try { res.json((await pool.query(`SELECT land_type as "landType", base_price as "basePrice", description FROM land_prices`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.post('/land-prices', async (req, res) => {
        try { await pool.query(`INSERT INTO land_prices VALUES ($1, $2, $3)`, [req.body.landType, req.body.basePrice, req.body.description]); res.json({status:'ok'}); }
        catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- MENU ITEMS (SIDEBAR) ---
    router.get('/menu-items', async (req, res) => {
        try { res.json((await pool.query(`SELECT * FROM menu_items ORDER BY order_index ASC`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/menu-items', async (req, res) => {
        try {
            await pool.query(`INSERT INTO menu_items (id, label, icon, roles, order_index, is_active, type, url) VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`, [req.body.id, req.body.label, req.body.icon, req.body.roles, req.body.order_index, req.body.is_active, req.body.type, req.body.url]);
            await logSystemAction(req, 'ADD_MENU', `Thêm mục menu: ${req.body.label}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // Cập nhật mục menu (Giải quyết lỗi 404)
    router.put('/menu-items/:id', async (req, res) => {
        const { id } = req.params;
        const { label, icon, roles, order_index, is_active, type, url } = req.body;
        try {
            await pool.query(
                `UPDATE menu_items 
                 SET label=$1, icon=$2, roles=$3, order_index=$4, is_active=$5, type=$6, url=$7 
                 WHERE id=$8`,
                [label, icon, roles, order_index, is_active, type, url, id]
            );
            await logSystemAction(req, 'UPDATE_MENU', `Cập nhật mục menu: ${label}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // Xóa mục menu (Giải quyết lỗi 404)
    router.delete('/menu-items/:id', async (req, res) => {
        const { id } = req.params;
        try {
            await pool.query(`DELETE FROM menu_items WHERE id = $1`, [id]);
            await logSystemAction(req, 'DELETE_MENU', `Xóa mục menu ID: ${id}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- SYSTEM SETTINGS ---
    router.get('/settings', async (req, res) => {
        try { res.json((await pool.query(`SELECT * FROM system_settings`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.post('/settings', async (req, res) => {
        try {
            for(const s of req.body.settings) {
                await pool.query(`INSERT INTO system_settings (key, value) VALUES ($1, $2) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value`, [s.key, s.value]);
            }
            await logSystemAction(req, 'UPDATE_SETTINGS', 'Cập nhật cấu hình hệ thống');
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}

import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

// Bộ nhớ đệm cho cấu trúc bảng (Schema Cache)
const SCHEMA_CACHE = new Map();

export default function(pool, logSystemAction) {
    const router = express.Router();

    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    /**
     * Hàm tìm tên cột với cơ chế Cache
     */
    const resolveTableColumns = async (tableName) => {
        // Kiểm tra trong cache trước
        if (SCHEMA_CACHE.has(tableName)) {
            return SCHEMA_CACHE.get(tableName);
        }

        try {
            const res = await pool.query(`
                SELECT column_name 
                FROM information_schema.columns 
                WHERE table_name = $1
            `, [tableName]);

            const dbColsMap = {};
            res.rows.forEach(r => {
                dbColsMap[r.column_name.toLowerCase()] = r.column_name;
            });

            const mapping = {};
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                let foundCol = standardKey;
                for (const candidate of candidates) {
                    if (dbColsMap[candidate]) {
                        foundCol = dbColsMap[candidate];
                        break;
                    }
                }
                mapping[standardKey] = foundCol;
            }

            // Lưu vào cache
            SCHEMA_CACHE.set(tableName, mapping);
            return mapping;
        } catch (e) {
            console.error(`Error resolving columns for ${tableName}:`, e);
            return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich' };
        }
    };

    const syncTableSchema = async (tableName) => {
        try {
            // Xóa cache cũ khi sync
            SCHEMA_CACHE.delete(tableName);
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const existingCols = res.rows.map(r => r.column_name.toLowerCase());

            const missingCols = [];
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) missingCols.push({ name: 'sodoto', type: 'TEXT' });
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) missingCols.push({ name: 'sothua', type: 'TEXT' });
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) missingCols.push({ name: 'loaidat', type: 'TEXT' });
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) missingCols.push({ name: 'dientich', type: 'NUMERIC' });

            if (missingCols.length > 0) {
                for (const col of missingCols) {
                    await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "${col.name}" ${col.type}`);
                }
                SCHEMA_CACHE.delete(tableName); // Refresh cache lần nữa
            }
            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
        } catch (e) {
            console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message);
        }
    };

    router.get('/spatial-tables', async (req, res) => {
        try {
            const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`);
            res.json(result.rows);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            await pool.query(`
                CREATE TABLE IF NOT EXISTS "${safeName}" (
                    gid SERIAL PRIMARY KEY,
                    sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC,
                    geometry GEOMETRY(Geometry, 4326),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${safeName}_geom_idx" ON "${safeName}" USING GIST (geometry)`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [safeName, displayName, description]);

            await syncTableSchema(safeName);
            await logSystemAction(req, 'CREATE_TABLE', `Tạo bảng mới: ${safeName}`);
            await pool.query('COMMIT');
            res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/link', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        try {
            const check = await pool.query(`SELECT to_regclass($1) as exists`, [tableName]);
            if (!check.rows[0].exists) throw new Error(`Bảng ${tableName} không tồn tại.`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [tableName, displayName, description]);

            await syncTableSchema(tableName);
            await logSystemAction(req, 'LINK_TABLE', `Liên kết bảng: ${tableName}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/rename', async (req, res) => {
        const { oldName, newName, displayName, description } = req.body;
        if (!oldName || !newName) return res.status(400).json({ error: "Thiếu tên bảng" });
        try {
            await pool.query(`UPDATE spatial_tables_registry SET table_name = $1, display_name = $2, description = $3 WHERE table_name = $4`, [newName, displayName, description, oldName]);
            SCHEMA_CACHE.delete(oldName);
            await logSystemAction(req, 'UPDATE_REGISTRY', `Cập nhật thông tin Registry: ${oldName} -> ${newName}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/unlink', async (req, res) => {
        try {
            SCHEMA_CACHE.delete(req.body.tableName);
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [req.body.tableName]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/spatial-tables/:name', async (req, res) => {
        const tableName = req.params.name;
        try {
            await pool.query('BEGIN');
            SCHEMA_CACHE.delete(tableName);
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [tableName]);
            await pool.query(`DROP TABLE IF EXISTS "${tableName}" CASCADE`);
            await logSystemAction(req, 'DROP_TABLE', `Xóa bảng: ${tableName}`);
            await pool.query('COMMIT');
            res.json({ status: 'ok' });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi } = req.query;
        if (!/^[a-zA-Z0-9_]+$/.test(table)) return res.status(400).json({ error: "Invalid table name" });

        try {
            const cols = await resolveTableColumns(table);
            let query = `
                SELECT gid, 
                "${cols.sodoto}" as sodoto, 
                "${cols.sothua}" as sothua, 
                "${cols.tenchu}" as tenchu, 
                "${cols.diachi}" as diachi, 
                "${cols.loaidat}" as loaidat, 
                "${cols.dientich}" as dientich, 
                ST_AsGeoJSON(geometry) as geometry 
                FROM "${table}" WHERE 1=1
            `;
            const params = [];
            let idx = 1;

            if (sodoto) { query += ` AND "${cols.sodoto}"::text ILIKE $${idx++}`; params.push(`%${sodoto}%`); }
            if (sothua) { query += ` AND "${cols.sothua}"::text ILIKE $${idx++}`; params.push(`%${sothua}%`); }
            if (tenchu) { query += ` AND "${cols.tenchu}" ILIKE $${idx++}`; params.push(`%${tenchu}%`); }
            if (diachi) { query += ` AND "${cols.diachi}" ILIKE $${idx++}`; params.push(`%${diachi}%`); }

            query += ` ORDER BY gid DESC LIMIT 100`;

            const result = await pool.query(query, params);
            res.json(result.rows.map(row => ({
                ...row,
                geometry: row.geometry ? JSON.parse(row.geometry) : null,
                kyhieumucd: row.loaidat, 
                shbando: row.sodoto,
                shthua: row.sothua
            })));
        } catch (e) {
            if (e.code === '42703') { 
                 SCHEMA_CACHE.delete(table);
                 await syncTableSchema(table);
                 return res.status(500).json({ error: "Database schema was updated. Please refresh." });
            }
            res.status(500).json({ error: e.message });
        }
    });

    router.get('/data/:table/extent', async (req, res) => {
        try {
            const result = await pool.query(`SELECT ST_XMin(ext) as xmin, ST_YMin(ext) as ymin, ST_XMax(ext) as xmax, ST_YMax(ext) as ymax FROM (SELECT ST_Extent(geometry) as ext FROM "${req.params.table}") as t`);
            res.json(result.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let geomSql = 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) {
                geomSql = `ST_SetSRID(ST_GeomFromGeoJSON($7), 4326)`;
                params.push(JSON.stringify(geometry));
            }
            const query = `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid`;
            const result = await pool.query(query, params);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            let idx = 7;
            if (geometry) {
                query += `, geometry=ST_SetSRID(ST_GeomFromGeoJSON($${idx}), 4326)`;
                params.push(JSON.stringify(geometry));
                idx++;
            }
            query += ` WHERE gid=$${idx}`;
            params.push(gid);
            await pool.query(query, params);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try {
            await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/upload', upload.single('file'), async (req, res) => {
        const { table } = req.params;
        const file = req.file;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, gid } = req.body; 
        if (!file) return res.status(400).json({ error: 'No file uploaded' });
        try {
            const cols = await resolveTableColumns(table);
            const buffer = fs.readFileSync(file.path);
            let geojson;
            if (file.originalname.endsWith('.zip')) geojson = await shp(buffer);
            else geojson = JSON.parse(buffer.toString());
            let geometry = null;
            if (Array.isArray(geojson)) geometry = geojson[0]?.features[0]?.geometry;
            else if (geojson.type === 'FeatureCollection') geometry = geojson.features[0]?.geometry;
            else if (geojson.type === 'Feature') geometry = geojson.geometry;
            else geometry = geojson;
            if (!geometry) throw new Error("Không tìm thấy dữ liệu hình học.");
            if (gid) {
                await pool.query(`UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6, geometry=ST_SetSRID(ST_GeomFromGeoJSON($7), 4326) WHERE gid=$8`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry), gid]);
            } else {
                await pool.query(`INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ST_SetSRID(ST_GeomFromGeoJSON($7), 4326))`, [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry)]);
            }
            fs.unlinkSync(file.path);
            res.json({ status: 'ok' });
        } catch (e) {
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: e.message });
        }
    });

    return router;
}

import express from 'express';

export default function(pool) {
    const router = express.Router();

    const TYPE_COLS = ['kyhieumucd', 'loaidat', 'mucdich', 'mdsd', 'kh_mucdich'];
    const AREA_COLS = ['dientich', 'dien_tich', 'shape_area', 'dt_phaply', 'st_area'];

    router.get('/dashboard', async (req, res) => {
        try {
            const registry = await pool.query('SELECT table_name, display_name FROM spatial_tables_registry');
            const tables = registry.rows;

            if (tables.length === 0) {
                return res.json({ totalParcels: 0, totalArea: 0, totalValue: 0, parcelsByType: [], valueByBranch: [] });
            }

            let totalParcels = 0;
            let totalArea = 0;
            const typeMap = {}; 
            const branchStats = []; 

            // Sử dụng Promise.all để truy vấn song song thay vì tuần tự (Nhanh hơn đáng kể)
            const results = await Promise.all(tables.map(async (table) => {
                const tableName = table.table_name;
                const displayName = table.display_name || tableName;

                try {
                    // Kiểm tra nhanh sự tồn tại của bảng và cột (không query data)
                    const colRes = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
                    if (colRes.rows.length === 0) return null;

                    const actualCols = colRes.rows.map(r => r.column_name.toLowerCase());
                    const typeCol = TYPE_COLS.find(c => actualCols.includes(c)) || 'loaidat';
                    const areaCol = AREA_COLS.find(c => actualCols.includes(c)) || 'dientich';

                    // Query tổng hợp nhanh
                    const statsQuery = `
                        SELECT 
                            COUNT(*)::int as count,
                            SUM(CASE WHEN "${areaCol}"::text ~ '^[0-9.]+$' THEN CAST("${areaCol}" AS NUMERIC) ELSE 0 END) as area
                        FROM "${tableName}"
                    `;
                    const basicStats = await pool.query(statsQuery);

                    // Lấy phân bổ loại đất (giới hạn 5 loại hàng đầu để tránh overhead)
                    const typeDistRes = await pool.query(`
                        SELECT COALESCE("${typeCol}"::text, 'Khác') as type, COUNT(*)::int as count
                        FROM "${tableName}"
                        GROUP BY "${typeCol}"
                        ORDER BY count DESC LIMIT 5
                    `);

                    return {
                        tableName,
                        displayName,
                        count: parseInt(basicStats.rows[0].count || 0),
                        area: parseFloat(basicStats.rows[0].area || 0),
                        types: typeDistRes.rows
                    };
                } catch (e) {
                    console.warn(`Skip table ${tableName}:`, e.message);
                    return null;
                }
            }));

            // Tổng hợp kết quả
            results.filter(Boolean).forEach(r => {
                totalParcels += r.count;
                totalArea += r.area;
                branchStats.push({ name: r.displayName, value: r.count });
                r.types.forEach(t => {
                    typeMap[t.type] = (typeMap[t.type] || 0) + t.count;
                });
            });

            const parcelsByType = Object.entries(typeMap)
                .map(([name, value]) => ({ name, value }))
                .sort((a, b) => b.value - a.value)
                .slice(0, 10);

            res.json({
                totalParcels,
                totalArea,
                totalValue: totalArea * 5000000, 
                parcelsByType,
                valueByBranch: branchStats
            });

        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    return router;
}

import React, { useState, useEffect, useRef } from 'react';
import { User, Message, UserRole } from '../types';
import { messageService, adminService, API_URL } from '../services/mockBackend';
import { Send, User as UserIcon, Search, Loader2, MessageSquare, ShieldCheck, Clock, Check, CheckCheck } from 'lucide-react';

interface MessagingProps {
    user: User;
}

const Messaging: React.FC<MessagingProps> = ({ user }) => {
    const [allUsers, setAllUsers] = useState<User[]>([]);
    const [selectedUser, setSelectedUser] = useState<User | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [inputText, setInputText] = useState('');
    const [loading, setLoading] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const scrollRef = useRef<HTMLDivElement>(null);
    const pollingRef = useRef<any>(null);

    useEffect(() => {
        loadUsers();
        return () => { if (pollingRef.current) clearInterval(pollingRef.current); };
    }, []);

    useEffect(() => {
        if (selectedUser) {
            loadMessages();
            // Tăng thời gian Polling lên 10 giây để giảm tải Server
            if (pollingRef.current) clearInterval(pollingRef.current);
            pollingRef.current = setInterval(loadMessages, 10000);
            return () => clearInterval(pollingRef.current);
        }
    }, [selectedUser]);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const loadUsers = async () => {
        try {
            const users = await adminService.getUsers();
            setAllUsers(users.filter(u => u.id !== user.id));
        } catch (e) { console.error(e); }
    };

    const loadMessages = async () => {
        if (!selectedUser) return;
        try {
            const data = await messageService.getMessages(selectedUser.id);
            // Chỉ cập nhật state nếu có dữ liệu thực sự thay đổi (giảm tải re-render)
            setMessages(prev => JSON.stringify(prev) !== JSON.stringify(data) ? data : prev);

            if (data.some(m => !m.is_read && m.receiver_id === user.id)) {
                await messageService.markAsRead(selectedUser.id);
            }
        } catch (e) { console.error(e); }
    };

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!inputText.trim() || !selectedUser) return;

        const content = inputText;
        setInputText('');
        try {
            await messageService.sendMessage(selectedUser.id, content);
            loadMessages();
        } catch (e) {
            console.error(e);
            alert("Lỗi gửi tin nhắn");
        }
    };

    const filteredUsers = allUsers.filter(u => 
        u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
        u.email.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const getAvatarUrl = (path?: string) => {
        if (!path) return null;
        if (path.startsWith('http') || path.startsWith('data:')) return path;
        return `${API_URL}${path.startsWith('/') ? path : '/' + path}`;
    };

    return (
        <div className="flex h-full bg-slate-950 overflow-hidden font-sans">
            {/* Sidebar: Danh sách người dùng */}
            <div className="w-80 border-r border-slate-800 flex flex-col bg-slate-900/50 backdrop-blur-md">
                <div className="p-6">
                    <h2 className="text-xl font-black text-white uppercase tracking-tighter mb-4 flex items-center gap-2">
                        <MessageSquare className="text-blue-500" size={20}/> Tin nhắn
                    </h2>
                    <div className="relative">
                        <Search className="absolute left-3 top-3 text-slate-500" size={16}/>
                        <input 
                            className="w-full bg-slate-800 border border-slate-700 rounded-xl p-2.5 pl-10 text-xs text-white focus:border-blue-500 outline-none"
                            placeholder="Tìm người dùng..."
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar px-3 space-y-1">
                    {filteredUsers.map(u => (
                        <button 
                            key={u.id}
                            onClick={() => setSelectedUser(u)}
                            className={`w-full flex items-center gap-3 p-3 rounded-2xl transition-all ${selectedUser?.id === u.id ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-400'}`}
                        >
                            <div className="w-10 h-10 rounded-full border-2 border-slate-700 overflow-hidden shrink-0">
                                {u.avatar ? (
                                    <img src={getAvatarUrl(u.avatar)!} className="w-full h-full object-cover" />
                                ) : (
                                    <div className="w-full h-full bg-slate-700 flex items-center justify-center text-[10px] font-bold">
                                        {u.name.charAt(0)}
                                    </div>
                                )}
                            </div>
                            <div className="text-left overflow-hidden">
                                <p className="text-xs font-black truncate">{u.name}</p>
                                <p className={`text-[9px] uppercase font-bold tracking-widest ${selectedUser?.id === u.id ? 'text-blue-100' : 'text-slate-500'}`}>
                                    {u.role}
                                </p>
                            </div>
                        </button>
                    ))}
                </div>
            </div>

            {/* Chat Area */}
            <div className="flex-1 flex flex-col relative bg-slate-950">
                {selectedUser ? (
                    <>
                        {/* Chat Header */}
                        <div className="p-4 border-b border-slate-800 bg-slate-900/30 flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-full border-2 border-blue-500/30 overflow-hidden">
                                    {selectedUser.avatar ? (
                                        <img src={getAvatarUrl(selectedUser.avatar)!} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full bg-slate-800 flex items-center justify-center text-blue-400">
                                            <UserIcon size={20}/>
                                        </div>
                                    )}
                                </div>
                                <div>
                                    <h3 className="text-sm font-black text-white">{selectedUser.name}</h3>
                                    <p className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-1">
                                        <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span> Trực tuyến
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* Messages List */}
                        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
                            {messages.map((m, idx) => {
                                const isMine = m.sender_id === user.id;
                                return (
                                    <div key={m.id} className={`flex ${isMine ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}>
                                        <div className={`max-w-[70%] group`}>
                                            <div className={`p-3.5 rounded-2xl text-sm ${isMine ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none'}`}>
                                                {m.content}
                                            </div>
                                            <div className={`flex items-center gap-2 mt-1 ${isMine ? 'justify-end' : 'justify-start'}`}>
                                                <span className="text-[9px] text-slate-500 font-bold">
                                                    {new Date(m.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                                </span>
                                                {isMine && (
                                                    m.is_read ? <CheckCheck size={12} className="text-blue-400"/> : <Check size={12} className="text-slate-600"/>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>

                        {/* Input Area */}
                        <form onSubmit={handleSendMessage} className="p-4 bg-slate-900/50 border-t border-slate-800">
                            <div className="flex gap-3">
                                <input 
                                    className="flex-1 bg-slate-800 border border-slate-700 rounded-2xl p-4 text-sm text-white focus:border-blue-500 outline-none shadow-inner"
                                    placeholder="Nhập nội dung tin nhắn..."
                                    value={inputText}
                                    onChange={e => setInputText(e.target.value)}
                                />
                                <button 
                                    type="submit"
                                    disabled={!inputText.trim()}
                                    className="bg-blue-600 hover:bg-blue-500 text-white p-4 rounded-2xl transition-all active:scale-90 disabled:opacity-50 shadow-lg shadow-blue-900/20"
                                >
                                    <Send size={20}/>
                                </button>
                            </div>
                        </form>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center p-10">
                        <div className="w-24 h-24 bg-blue-600/10 rounded-full flex items-center justify-center mb-6 border border-blue-500/20">
                            <MessageSquare size={40} className="text-blue-400 opacity-50" />
                        </div>
                        <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Trung tâm tin nhắn</h2>
                        <p className="text-slate-500 max-w-xs text-sm">Chọn một người dùng từ danh sách bên trái để bắt đầu cuộc trò chuyện.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Messaging;

