const Messaging: React.FC<MessagingProps> = ({ user }) => {
    const [allUsers, setAllUsers] = useState<User[]>([]);
    const [selectedUser, setSelectedUser] = useState<User | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [inputText, setInputText] = useState('');
    const [loading, setLoading] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [currentUserInfo, setCurrentUserInfo] = useState<User | null>(null);
    const scrollRef = useRef<HTMLDivElement>(null);
    const pollingRef = useRef<any>(null);

    useEffect(() => {
        loadUsers();
        loadCurrentUserInfo();
        return () => { if (pollingRef.current) clearInterval(pollingRef.current); };
    }, []);

    const loadCurrentUserInfo = async () => {
        try {
            const freshUser = await adminService.getUsers();
            const current = freshUser.find(u => u.id === user.id);
            if (current) setCurrentUserInfo(current);
        } catch (e) {}
    };

    useEffect(() => {
        if (selectedUser) {
            loadMessages();
            // Tăng thời gian Polling lên 10 giây để giảm tải Server
            if (pollingRef.current) clearInterval(pollingRef.current);
            pollingRef.current = setInterval(loadMessages, 10000);
            return () => clearInterval(pollingRef.current);
        }
    }, [selectedUser]);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const loadUsers = async () => {
        try {
            const users = await adminService.getUsers();
            setAllUsers(users.filter(u => u.id !== user.id));
        } catch (e) { console.error(e); }
    };

    const loadMessages = async () => {
        if (!selectedUser) return;
        try {
            const data = await messageService.getMessages(selectedUser.id);
            // Chỉ cập nhật state nếu có dữ liệu thực sự thay đổi (giảm tải re-render)
            setMessages(prev => JSON.stringify(prev) !== JSON.stringify(data) ? data : prev);

            if (data.some(m => !m.is_read && m.receiver_id === user.id)) {
                await messageService.markAsRead(selectedUser.id);
            }
        } catch (e) { console.error(e); }
    };

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!inputText.trim() || !selectedUser) return;

        if (currentUserInfo && currentUserInfo.can_chat === false) {
            alert("Tài khoản của bạn đang bị hạn chế quyền nhắn tin.");
            return;
        }

        const content = inputText;
        setInputText('');
        try {
            await messageService.sendMessage(selectedUser.id, content);
            loadMessages();
        } catch (e: any) {
            console.error(e);
            alert(e.message || "Lỗi gửi tin nhắn");
        }
    };

    const handleDeleteMessage = async (msgId: number) => {
        if (!confirm("Bạn có chắc chắn muốn xóa tin nhắn này?")) return;
        try {
            await messageService.deleteMessage(msgId);
            setMessages(prev => prev.filter(m => m.id !== msgId));
        } catch (e: any) {
            alert(e.message || "Lỗi xóa tin nhắn");
        }
    };

    const filteredUsers = allUsers.filter(u => 
        u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
        u.email.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const getAvatarUrl = (path?: string) => {
        if (!path) return null;
        if (path.startsWith('http') || path.startsWith('data:')) return path;
        return `${API_URL}${path.startsWith('/') ? path : '/' + path}`;
    };

    const canSend = selectedUser && currentUserInfo?.can_chat !== false;

    return (
        <div className="flex h-full bg-slate-950 overflow-hidden font-sans">
            {/* Sidebar: Danh sách người dùng */}
            <div className="w-80 border-r border-slate-800 flex flex-col bg-slate-900/50 backdrop-blur-md">
                <div className="p-6">
                    <h2 className="text-xl font-black text-white uppercase tracking-tighter mb-4 flex items-center gap-2">
                        <MessageSquare className="text-blue-500" size={20}/> Tin nhắn
                    </h2>
                    <div className="relative">
                        <Search className="absolute left-3 top-3 text-slate-500" size={16}/>
                        <input 
                            className="w-full bg-slate-800 border border-slate-700 rounded-xl p-2.5 pl-10 text-xs text-white focus:border-blue-500 outline-none"
                            placeholder="Tìm người dùng..."
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar px-3 space-y-1">
                    {filteredUsers.map(u => (
                        <button 
                            key={u.id}
                            onClick={() => setSelectedUser(u)}
                            className={`w-full flex items-center gap-3 p-3 rounded-2xl transition-all ${selectedUser?.id === u.id ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-400'}`}
                        >
                            <div className="w-10 h-10 rounded-full border-2 border-slate-700 overflow-hidden shrink-0">
                                {u.avatar ? (
                                    <img src={getAvatarUrl(u.avatar)!} className="w-full h-full object-cover" />
                                ) : (
                                    <div className="w-full h-full bg-slate-700 flex items-center justify-center text-[10px] font-bold">
                                        {u.name.charAt(0)}
                                    </div>
                                )}
                            </div>
                            <div className="text-left overflow-hidden">
                                <p className="text-xs font-black truncate">{u.name}</p>
                                <p className={`text-[9px] uppercase font-bold tracking-widest ${selectedUser?.id === u.id ? 'text-blue-100' : 'text-slate-500'}`}>
                                    {u.role}
                                </p>
                            </div>
                        </button>
                    ))}
                </div>
            </div>

            {/* Chat Area */}
            <div className="flex-1 flex flex-col relative bg-slate-950">
                {selectedUser ? (
                    <>
                        {/* Chat Header */}
                        <div className="p-4 border-b border-slate-800 bg-slate-900/30 flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-full border-2 border-blue-500/30 overflow-hidden">
                                    {selectedUser.avatar ? (
                                        <img src={getAvatarUrl(selectedUser.avatar)!} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full bg-slate-800 flex items-center justify-center text-blue-400">
                                            <UserIcon size={20}/>
                                        </div>
                                    )}
                                </div>
                                <div>
                                    <h3 className="text-sm font-black text-white">{selectedUser.name}</h3>
                                    <p className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-1">
                                        <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span> Trực tuyến
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* Messages List */}
                        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
                            {messages.map((m, idx) => {
                                const isMine = m.sender_id === user.id;
                                return (
                                    <div key={m.id} className={`flex ${isMine ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 group`}>
                                        <div className={`max-w-[70%] relative`}>
                                            <div className={`p-3.5 rounded-2xl text-sm ${isMine ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none'}`}>
                                                {m.content}
                                            </div>

                                            {/* Delete Button (Only for mine) */}
                                            {isMine && (
                                                <button 
                                                    onClick={() => handleDeleteMessage(m.id)}
                                                    className="absolute -left-8 top-1/2 -translate-y-1/2 p-1.5 text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                                    title="Xóa tin nhắn"
                                                >
                                                    <Trash2 size={14}/>
                                                </button>
                                            )}

                                            <div className={`flex items-center gap-2 mt-1 ${isMine ? 'justify-end' : 'justify-start'}`}>
                                                <span className="text-[9px] text-slate-500 font-bold">
                                                    {new Date(m.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                                </span>
                                                {isMine && (
                                                    m.is_read ? <CheckCheck size={12} className="text-blue-400"/> : <Check size={12} className="text-slate-600"/>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>

                        {/* Input Area */}
                        <form onSubmit={handleSendMessage} className="p-4 bg-slate-900/50 border-t border-slate-800 relative">
                            {!canSend && (
                                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-10 flex items-center justify-center gap-3">
                                    <AlertCircle className="text-orange-500" size={20}/>
                                    <span className="text-xs font-black text-white uppercase tracking-widest">Bạn đã bị hạn chế quyền nhắn tin bởi quản trị viên</span>
                                </div>
                            )}
                            <div className="flex gap-3">
                                <input 
                                    className="flex-1 bg-slate-800 border border-slate-700 rounded-2xl p-4 text-sm text-white focus:border-blue-500 outline-none shadow-inner disabled:opacity-50"
                                    placeholder="Nhập nội dung tin nhắn..."
                                    value={inputText}
                                    onChange={e => setInputText(e.target.value)}
                                    disabled={!canSend}
                                />
                                <button 
                                    type="submit"
                                    disabled={!inputText.trim() || !canSend}
                                    className="bg-blue-600 hover:bg-blue-500 text-white p-4 rounded-2xl transition-all active:scale-90 disabled:opacity-50 shadow-lg shadow-blue-900/20"
                                >
                                    <Send size={20}/>
                                </button>
                            </div>
                        </form>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center p-10">
                        <div className="w-24 h-24 bg-blue-600/10 rounded-full flex items-center justify-center mb-6 border border-blue-500/20">
                            <MessageSquare size={40} className="text-blue-400 opacity-50" />
                        </div>
                        <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Trung tâm tin nhắn</h2>
                        <p className="text-slate-500 max-w-xs text-sm">Chọn một người dùng từ danh sách bên trái để bắt đầu cuộc trò chuyện.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Messaging;

import React, { useState, useEffect, useRef } from 'react';
import { User, Message, UserRole } from '../types';
import { messageService, adminService, API_URL } from '../services/mockBackend';
import { Send, User as UserIcon, Search, Loader2, MessageSquare, ShieldCheck, Clock, Check, CheckCheck, Trash2, AlertCircle, X, Info, AlertTriangle, CheckCircle2 } from 'lucide-react';

interface MessagingProps {
    user: User;
}

const Messaging: React.FC<MessagingProps> = ({ user }) => {
    const [allUsers, setAllUsers] = useState<User[]>([]);
    const [selectedUser, setSelectedUser] = useState<User | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [inputText, setInputText] = useState('');
    const [loading, setLoading] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [currentUserInfo, setCurrentUserInfo] = useState<User | null>(null);
    const scrollRef = useRef<HTMLDivElement>(null);
    const pollingRef = useRef<any>(null);

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'success' | 'error' | 'warning';
        title: string;
        message: string;
        onConfirm?: () => void;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    useEffect(() => {
        loadUsers();
        loadCurrentUserInfo();
        return () => { if (pollingRef.current) clearInterval(pollingRef.current); };
    }, []);

    const loadCurrentUserInfo = async () => {
        try {
            const freshUser = await adminService.getUsers();
            const current = freshUser.find(u => u.id === user.id);
            if (current) setCurrentUserInfo(current);
        } catch (e) {}
    };

    useEffect(() => {
        if (selectedUser) {
            loadMessages();
            if (pollingRef.current) clearInterval(pollingRef.current);
            pollingRef.current = setInterval(loadMessages, 10000);
            return () => clearInterval(pollingRef.current);
        }
    }, [selectedUser]);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const loadUsers = async () => {
        try {
            const users = await adminService.getUsers();
            setAllUsers(users.filter(u => u.id !== user.id));
        } catch (e) { console.error(e); }
    };

    const loadMessages = async () => {
        if (!selectedUser) return;
        try {
            const data = await messageService.getMessages(selectedUser.id);
            setMessages(prev => JSON.stringify(prev) !== JSON.stringify(data) ? data : prev);

            if (data.some(m => !m.is_read && m.receiver_id === user.id)) {
                await messageService.markAsRead(selectedUser.id);
            }
        } catch (e) {}
    };

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!inputText.trim() || !selectedUser) return;

        if (currentUserInfo && currentUserInfo.can_chat === false) {
            showDialog('warning', 'Hạn chế quyền', 'Tài khoản của bạn đã bị quản trị viên khóa chức năng nhắn tin nội bộ.');
            return;
        }

        const content = inputText;
        setInputText('');
        try {
            await messageService.sendMessage(selectedUser.id, content);
            loadMessages();
        } catch (e: any) {
            showDialog('error', 'Lỗi gửi tin', e.message || 'Không thể gửi tin nhắn lúc này. Server có thể đang quá tải.');
        }
    };

    const handleDeleteMessage = (msgId: number) => {
        showDialog('confirm', 'Xác nhận xóa', 'Bạn có chắc chắn muốn xóa tin nhắn này không?', async () => {
            try {
                await messageService.deleteMessage(msgId);
                setMessages(prev => prev.filter(m => m.id !== msgId));
            } catch (e: any) {
                showDialog('error', 'Lỗi xóa tin', e.message || 'Không thể xóa tin nhắn.');
            }
        });
    };

    const filteredUsers = allUsers.filter(u => 
        u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
        u.email.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const getAvatarUrl = (path?: string) => {
        if (!path) return null;
        if (path.startsWith('http') || path.startsWith('data:')) return path;
        return `${API_URL}${path.startsWith('/') ? path : '/' + path}`;
    };

    const canSend = selectedUser && currentUserInfo?.can_chat !== false;

    return (
        <div className="flex h-full bg-slate-950 overflow-hidden font-sans relative">
            {/* Sidebar */}
            <div className="w-80 border-r border-slate-800 flex flex-col bg-slate-900/50 backdrop-blur-md">
                <div className="p-6">
                    <h2 className="text-xl font-black text-white uppercase tracking-tighter mb-4 flex items-center gap-2">
                        <MessageSquare className="text-blue-500" size={20}/> Tin nhắn
                    </h2>
                    <div className="relative">
                        <Search className="absolute left-3 top-3 text-slate-500" size={16}/>
                        <input 
                            className="w-full bg-slate-800 border border-slate-700 rounded-xl p-2.5 pl-10 text-xs text-white focus:border-blue-500 outline-none"
                            placeholder="Tìm người dùng..."
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                        />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar px-3 space-y-1">
                    {filteredUsers.map(u => (
                        <button 
                            key={u.id}
                            onClick={() => setSelectedUser(u)}
                            className={`w-full flex items-center gap-3 p-3 rounded-2xl transition-all ${selectedUser?.id === u.id ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800 text-slate-400'}`}
                        >
                            <div className="w-10 h-10 rounded-full border-2 border-slate-700 overflow-hidden shrink-0">
                                {u.avatar ? (
                                    <img src={getAvatarUrl(u.avatar)!} className="w-full h-full object-cover" />
                                ) : (
                                    <div className="w-full h-full bg-slate-700 flex items-center justify-center text-[10px] font-bold">
                                        {u.name.charAt(0)}
                                    </div>
                                )}
                            </div>
                            <div className="text-left overflow-hidden">
                                <p className="text-xs font-black truncate">{u.name}</p>
                                <p className={`text-[9px] uppercase font-bold tracking-widest ${selectedUser?.id === u.id ? 'text-blue-100' : 'text-slate-500'}`}>
                                    {u.role}
                                </p>
                            </div>
                        </button>
                    ))}
                </div>
            </div>

            {/* Chat Area */}
            <div className="flex-1 flex flex-col relative bg-slate-950">
                {selectedUser ? (
                    <>
                        <div className="p-4 border-b border-slate-800 bg-slate-900/30 flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-full border-2 border-blue-500/30 overflow-hidden">
                                    {selectedUser.avatar ? (
                                        <img src={getAvatarUrl(selectedUser.avatar)!} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full bg-slate-800 flex items-center justify-center text-blue-400">
                                            <UserIcon size={20}/>
                                        </div>
                                    )}
                                </div>
                                <div>
                                    <h3 className="text-sm font-black text-white">{selectedUser.name}</h3>
                                    <p className="text-[10px] text-emerald-500 font-bold uppercase flex items-center gap-1">
                                        <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span> Trực tuyến
                                    </p>
                                </div>
                            </div>
                        </div>

                        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
                            {messages.map((m) => {
                                const isMine = m.sender_id === user.id;
                                return (
                                    <div key={m.id} className={`flex ${isMine ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 group`}>
                                        <div className={`max-w-[70%] relative`}>
                                            <div className={`p-3.5 rounded-2xl text-sm ${isMine ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none'}`}>
                                                {m.content}
                                            </div>
                                            {isMine && (
                                                <button 
                                                    onClick={() => handleDeleteMessage(m.id)}
                                                    className="absolute -left-8 top-1/2 -translate-y-1/2 p-1.5 text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                                                    title="Xóa tin nhắn"
                                                >
                                                    <Trash2 size={14}/>
                                                </button>
                                            )}
                                            <div className={`flex items-center gap-2 mt-1 ${isMine ? 'justify-end' : 'justify-start'}`}>
                                                <span className="text-[9px] text-slate-500 font-bold">
                                                    {new Date(m.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                                </span>
                                                {isMine && (m.is_read ? <CheckCheck size={12} className="text-blue-400"/> : <Check size={12} className="text-slate-600"/>)}
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>

                        <form onSubmit={handleSendMessage} className="p-4 bg-slate-900/50 border-t border-slate-800 relative">
                            {!canSend && (
                                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-10 flex items-center justify-center gap-3">
                                    <AlertCircle className="text-orange-500" size={20}/>
                                    <span className="text-xs font-black text-white uppercase tracking-widest">Bạn đang bị hạn chế quyền nhắn tin nội bộ</span>
                                </div>
                            )}
                            <div className="flex gap-3">
                                <input 
                                    className="flex-1 bg-slate-800 border border-slate-700 rounded-2xl p-4 text-sm text-white focus:border-blue-500 outline-none shadow-inner disabled:opacity-50"
                                    placeholder="Nhập nội dung tin nhắn..."
                                    value={inputText}
                                    onChange={e => setInputText(e.target.value)}
                                    disabled={!canSend}
                                />
                                <button 
                                    type="submit"
                                    disabled={!inputText.trim() || !canSend}
                                    className="bg-blue-600 hover:bg-blue-500 text-white p-4 rounded-2xl transition-all active:scale-90 disabled:opacity-50 shadow-lg"
                                >
                                    <Send size={20}/>
                                </button>
                            </div>
                        </form>
                    </>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center p-10">
                        <div className="w-24 h-24 bg-blue-600/10 rounded-full flex items-center justify-center mb-6 border border-blue-500/20">
                            <MessageSquare size={40} className="text-blue-400 opacity-50" />
                        </div>
                        <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">Trung tâm tin nhắn</h2>
                        <p className="text-slate-500 max-w-xs text-sm">Chọn một người dùng từ danh sách bên trái để bắt đầu cuộc trò chuyện.</p>
                    </div>
                )}
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-slate-900 rounded-[2.5rem] w-full max-w-sm border border-slate-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertCircle size={28}/></div>}
                            {dialog.type === 'confirm' && <div className="w-14 h-14 bg-orange-500/20 text-orange-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'warning' && <div className="w-14 h-14 bg-yellow-500/20 text-yellow-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'alert' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <div className="flex gap-2 w-full">
                                {dialog.type === 'confirm' ? (
